use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Function to extract text from PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';

    # Loop through each page
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->page($page);
        $text .= $page_obj->text;
    }

    return $text;
}

